// the provided (workos_org_id, workos_membership_id) pairs and soft-deletes any
// other relationships where the org has a non-NULL workos_id. Orgs without a
// workos_id are unaffected. Other users' memberships are never modified.
func (q *Queries) SetUserWorkOSMemberships(ctx context.Context, arg SetUserWorkOSMembershipsParams) error {
	_, err := q.db.Exec(ctx, setUserWorkOSMemberships, arg.UserID, arg.WorkosOrgIds, arg.WorkosMembershipIds)
	return err
}

const syncUserOrganizationRoleAssignments = `-- name: SyncUserOrganizationRoleAssignments :exec
WITH input_role_urns AS (
    SELECT 'role:organization:' || id::text AS role_urn
    FROM organization_roles
    WHERE organization_id = $3
      AND workos_slug = ANY($5::text[])
      AND deleted IS FALSE
      AND workos_deleted IS FALSE
    UNION ALL
    SELECT 'role:global:' || id::text AS role_urn
    FROM global_roles
    WHERE workos_slug = ANY($5::text[])
      AND deleted IS FALSE
      AND workos_deleted IS FALSE
),
upserted AS (
    INSERT INTO organization_role_assignments (
        organization_id,
        workos_user_id,
        user_id,
        role_urn,
        workos_membership_id,
        workos_updated_at,
        workos_last_event_id
    )
    SELECT
        $3,
        $4,
        $6,
        input_role_urns.role_urn,
        $7,
        $1,
        $2
    FROM input_role_urns
    ON CONFLICT (organization_id, workos_user_id, role_urn) WHERE deleted_at IS NULL DO UPDATE SET
        -- COALESCE preserves a backfilled user_id if the sync fires before the Gram user exists.
        user_id = COALESCE(EXCLUDED.user_id, organization_role_assignments.user_id),
        workos_membership_id = EXCLUDED.workos_membership_id,
        workos_updated_at = EXCLUDED.workos_updated_at,
        workos_last_event_id = EXCLUDED.workos_last_event_id,
        deleted_at = NULL,
        updated_at = clock_timestamp()
    RETURNING role_urn
)
UPDATE organization_role_assignments
SET workos_updated_at = $1,
    workos_last_event_id = $2,
    deleted_at = COALESCE(deleted_at, clock_timestamp()),
    updated_at = clock_timestamp()
WHERE organization_role_assignments.organization_id = $3
  AND organization_role_assignments.workos_user_id = $4
  AND organization_role_assignments.deleted_at IS NULL
  AND organization_role_assignments.role_urn NOT IN (SELECT input_role_urns.role_urn FROM input_role_urns)
`

type SyncUserOrganizationRoleAssignmentsParams struct {
	WorkosUpdatedAt    pgtype.Timestamptz
	WorkosLastEventID  pgtype.Text
	OrganizationID     string
	WorkosUserID       string
	WorkosRoleSlugs    []string
	UserID             pgtype.Text
	WorkosMembershipID pgtype.Text
}

// Declaratively set all WorkOS role assignments for a known Gram user in an
// org. Role slugs are resolved from role sync tables and stale assignments for
// this WorkOS user are removed.
func (q *Queries) SyncUserOrganizationRoleAssignments(ctx context.Context, arg SyncUserOrganizationRoleAssignmentsParams) error {
	_, err := q.db.Exec(ctx, syncUserOrganizationRoleAssignments,
		arg.WorkosUpdatedAt,
		arg.WorkosLastEventID,
		arg.OrganizationID,
		arg.WorkosUserID,
		arg.WorkosRoleSlugs,
		arg.UserID,
		arg.WorkosMembershipID,
	)
	return err
}

const upsertOrganizationMetadata = `-- name: UpsertOrganizationMetadata :one
INSERT INTO organization_metadata (
    id,
    name,
    slug,
    workos_id,
    whitelisted
) VALUES (
    $1,
    $2,
    $3,
    $4,
    COALESCE($5::boolean, TRUE)
)
ON CONFLICT (id) DO UPDATE SET
    name = EXCLUDED.name,
    slug = EXCLUDED.slug,
    -- TODO: remove COALESCE once WorkOS org migration is complete and all orgs reliably provide workos_id.
    workos_id = COALESCE(EXCLUDED.workos_id, organization_metadata.workos_id),
    whitelisted = CASE
        WHEN $5::boolean IS NOT NULL THEN $5::boolean
        ELSE organization_metadata.whitelisted
    END,
    updated_at = clock_timestamp()
RETURNING id, name, slug, gram_account_type, sso_connection_id, workos_id, workos_updated_at, workos_last_event_id, svix_app_id, webhooks_enabled, whitelisted, free_trial_started_at, free_trial_ends_at, created_at, updated_at, disabled_at
`

type UpsertOrganizationMetadataParams struct {
	ID          string
	Name        string
	Slug        string
	WorkosID    pgtype.Text
	Whitelisted pgtype.Bool
}

func (q *Queries) UpsertOrganizationMetadata(ctx context.Context, arg UpsertOrganizationMetadataParams) (OrganizationMetadatum, error) {
	row := q.db.QueryRow(ctx, upsertOrganizationMetadata,
		arg.ID,
		arg.Name,
		arg.Slug,
		arg.WorkosID,
		arg.Whitelisted,
	)
	var i OrganizationMetadatum
	err := row.Scan(
		&i.ID,
		&i.Name,
		&i.Slug,
		&i.GramAccountType,
		&i.SsoConnectionID,
		&i.WorkosID,
		&i.WorkosUpdatedAt,
		&i.WorkosLastEventID,
		&i.SvixAppID,
		&i.WebhooksEnabled,
		&i.Whitelisted,
		&i.FreeTrialStartedAt,
		&i.FreeTrialEndsAt,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.DisabledAt,
	)
	return i, err
}

